#nullable enable // autogenerated

using MVZ2.GameContent.Buffs;
using MVZ2.GameContent.Obstacles;
using MVZ2.Vanilla.Callbacks;
using PVZEngine.Buffs;
using PVZEngine.Callbacks;
using PVZEngine.Definitions;
using PVZEngine.Entities;

namespace MVZ2.GameContent.Projectiles
{
    [AutoEntityBehaviourDefinition(VanillaProjectileNames.Squid)]
    public class Squid : EntityBehaviourDefinition
    {
        public Squid(string nsp, string name) : base(nsp, name)
        {
            AddTrigger(VanillaLevelCallbacks.POST_PROJECTILE_HIT, PostHitEntityCallback);
        }

        private void PostHitEntityCallback(VanillaLevelCallbacks.PostProjectileHitParams param, CallbackResult result)
        {
            var hitResult = param.hit;
            var projectile = hitResult.Projectile;
            if (!projectile.Definition.HasBehaviour(this))
                return;
            if (hitResult.Shield != null)
                return;

            var other = hitResult.Other;
            if (other == null || other.Type != EntityTypes.PLANT || other.IsDead)
                return;

            // 检查是否已被标记
            if (SquidDrownedMarkedBuff.IsMarked(other))
                return;

            var level = other.Level;

            // 1. 为器械添加标记 buff（休眠 + 记录关联）
            var markBuff = other.AddBuff<SquidDrownedMarkedBuff>();
            if (markBuff != null)
            {
                // 2. 在原位置生成敌方障碍物"鱿鱼笼"
            var cage = level.Spawn(VanillaObstacleID.SquidCage, other.Position, other);
                if (cage != null)
                {
                    // 双向关联：障碍物记录器械 ID
                    SquidCageBehaviour.SetTrappedPlantID(cage, new EntityID(other));
                    // buff 记录障碍物 ID（用于器械被其他方式移除时清理障碍物）
                    SquidDrownedMarkedBuff.SetCageID(markBuff, new EntityID(cage));
                }
            }
        }
    }
}
